// Gemini AI Chatbot Service for Farm2Table
// Uses Google's Generative AI (Gemini) API - free tier

const GEMINI_API_KEY = 'AIzaSyAkjzBlc4jgpPfXULkfFd0_TLHT9tpZKjY';
const GEMINI_API_URL = 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent';

const SYSTEM_PROMPT = `You are Farm2Table Assistant 🌱, a friendly and knowledgeable AI helper for the Farm2Table app — a platform connecting farmers directly with buyers for fresh, local produce.

Your role:
- Help buyers find products, understand pricing, and navigate the app
- Help farmers manage their listings and understand best practices
- Answer questions about organic farming, seasonal produce, and nutrition
- Provide delivery information and order tracking help
- Be warm, helpful, and concise in your responses
- Use relevant emojis sparingly to keep things friendly

Keep responses short (2-3 sentences) unless the user asks for detailed information.`;

let conversationHistory = [];

export const resetConversation = () => {
  conversationHistory = [];
};

export const sendMessageToGemini = async (userMessage) => {
  conversationHistory.push({
    role: 'user',
    parts: [{ text: userMessage }],
  });

  const contents = [
    {
      role: 'user',
      parts: [{ text: SYSTEM_PROMPT }],
    },
    {
      role: 'model',
      parts: [{ text: 'Understood! I\'m Farm2Table Assistant 🌱. I\'m here to help with anything related to Farm2Table — finding fresh produce, managing listings, delivery tracking, and more. How can I help you today?' }],
    },
    ...conversationHistory,
  ];

  try {
    const response = await fetch(`${GEMINI_API_URL}?key=${GEMINI_API_KEY}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        contents,
        generationConfig: {
          temperature: 0.7,
          topK: 40,
          topP: 0.95,
          maxOutputTokens: 512,
        },
        safetySettings: [
          { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_MEDIUM_AND_ABOVE' },
          { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_MEDIUM_AND_ABOVE' },
          { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_MEDIUM_AND_ABOVE' },
          { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_MEDIUM_AND_ABOVE' },
        ],
      }),
    });

    const data = await response.json();

    if (!response.ok) {
      throw new Error(data.error?.message || 'Failed to get response from Gemini');
    }

    const aiMessage = data.candidates?.[0]?.content?.parts?.[0]?.text || 'Sorry, I couldn\'t process that. Please try again.';

    conversationHistory.push({
      role: 'model',
      parts: [{ text: aiMessage }],
    });

    return aiMessage;
  } catch (error) {
    console.error('Gemini API Error:', error);
    // Remove the failed user message from history
    conversationHistory.pop();
    throw error;
  }
};
